mapper.select:
SELECT MAX(m.id) AS id, m.biz_no AS bizNo, ANY_VALUE(m.msg_type) AS msgType, ANY_VALUE(m.title) AS title, ANY_VALUE(m.summary) AS summary, ANY_VALUE(m.link_url) AS linkUrl, ANY_VALUE(m.scope) AS scope, COUNT(*) AS audienceCount, MAX(m.created_at) AS createdAt, ANY_VALUE(m.created_by) AS createdBy, (SELECT COUNT(DISTINCT mr.user_id) FROM u_message_read mr INNER JOIN u_message mm ON mm.id = mr.message_id WHERE mm.biz_no = m.biz_no AND mm.is_deleted = 0) AS readCount FROM u_message m WHERE m.is_deleted = 0 AND m.msg_type = #{msgType}
AND (m.title LIKE CONCAT('%', #{keyword}, '%') OR m.summary LIKE CONCAT('%', #{keyword}, '%'))
GROUP BY m.biz_no ORDER BY MAX(m.created_at) DESC LIMIT #{offset}, #{size}
